import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";
import { generatedPosts } from "@/lib/generated-posts";
import {
  getBlogCategories,
  getBlogCategoryBySlug,
  getPostsByBlogCategory,
} from "@/lib/blog-categories";

type Props = {
  params: Promise<{ categoria: string }>;
};


export function generateStaticParams() {
  return getBlogCategories().map((category) => ({
    categoria: category.slug,
  }));
}

export async function generateMetadata({ params }: Props) {
  const { categoria: categorySlug } = await params;
  const category = getBlogCategoryBySlug(categorySlug);

  if (!category) {
    notFound();
  }

  return {
    title: `${category.label} | Blog`,
    description: category.description,
    openGraph: {
      title: `${category.label} | Blog Tupiniquim`,
      description: category.description,
      type: "website" as const,
    },
  };
}

function formatDate(date: string) {
  const parsedDate = new Date(`${date}T12:00:00`);

  if (Number.isNaN(parsedDate.getTime())) {
    return date;
  }

  return new Intl.DateTimeFormat("pt-BR", {
    day: "2-digit",
    month: "long",
    year: "numeric",
  }).format(parsedDate);
}

export default async function CategoryPage({ params }: Props) {
  const { categoria: categorySlug } = await params;
  const category = getBlogCategoryBySlug(categorySlug);

  if (!category) {
    notFound();
  }

  const categories = getBlogCategories();
  const posts = getPostsByBlogCategory(generatedPosts, category.slug);
  const publicationLabel = posts.length === 1 ? "publicação" : "publicações";

  return (
    <main className="category-page">
      <nav className="category-navigation" aria-label="Editorias do blog">
        <span className="category-navigation-label">Editorias</span>

        <div className="category-navigation-list">
          <Link href="/blog" className="category-navigation-link">
            Todos
          </Link>

          {categories.map((item) => {
            const isActive = item.slug === category.slug;

            return (
              <Link
                key={item.slug}
                href={`/blog/categoria/${item.slug}`}
                className={`category-navigation-link${
                  isActive ? " category-navigation-link-active" : ""
                }`}
                aria-current={isActive ? "page" : undefined}
              >
                {item.label}
              </Link>
            );
          })}
        </div>
      </nav>

      <header className="category-header">
        <p className="category-eyebrow">Editoria</p>
        <h1>{category.label}</h1>
        <p className="category-description">{category.description}</p>
        <p className="category-count">
          {posts.length} {publicationLabel}
        </p>
      </header>

      <section
        className="category-results"
        aria-label={`Publicações de ${category.label}`}
      >
        {posts.length > 0 ? (
          <div className="category-grid">
            {posts.map((post) => (
              <article className="category-card" key={post.slug}>
                <Link
                  href={`/blog/${post.slug}`}
                  className="category-card-link"
                >
                  {post.image && (
                    <div className="category-image-wrapper">
                      <Image
                        src={post.image}
                        alt={post.title}
                        width={720}
                        height={450}
                        className="category-image"
                      />
                    </div>
                  )}

                  <div className="category-card-content">
                    <p className="category-card-label">{category.label}</p>
                    <h2 className="category-card-title">{post.title}</h2>
                    <p className="category-card-description">
                      {post.description}
                    </p>
                    <time className="category-card-date" dateTime={post.date}>
                      {formatDate(post.date)}
                    </time>
                  </div>
                </Link>
              </article>
            ))}
          </div>
        ) : (
          <p className="category-empty">
            Nenhuma publicação disponível nesta editoria no momento.
          </p>
        )}
      </section>

      <style>{`
        .category-page {
          width: 100%;
        }

        .category-navigation {
          display: flex;
          align-items: center;
          gap: 24px;
          overflow-x: auto;
          padding: 15px 0;
          border-bottom: 1px solid #cfcfcf;
          white-space: nowrap;
        }

        .category-navigation-label {
          color: #111;
          font-weight: 800;
          text-transform: uppercase;
        }

        .category-navigation-list {
          display: flex;
          align-items: center;
        }

        .category-navigation-link {
          padding: 2px 18px 7px;
          border-bottom: 3px solid transparent;
          border-left: 1px solid #cfcfcf;
          color: #333;
          font-weight: 600;
          text-decoration: none;
          transition: color 0.2s ease, border-color 0.2s ease;
        }

        .category-navigation-link:hover,
        .category-navigation-link-active {
          border-bottom-color: #2e7d32;
          color: #2e7d32;
        }

        .category-header {
          padding: 58px 0 38px;
          border-bottom: 4px solid #111;
        }

        .category-eyebrow,
        .category-card-label {
          margin: 0;
          color: #2e7d32;
          font-size: 0.75rem;
          font-weight: 700;
          letter-spacing: 0.1em;
          text-transform: uppercase;
        }

        .category-header h1 {
          margin: 8px 0 14px;
          color: #111;
          font-size: clamp(2.5rem, 6vw, 5rem);
          line-height: 0.98;
          letter-spacing: -0.04em;
        }

        .category-description {
          max-width: 800px;
          margin: 0;
          color: #444;
          font-size: 1.1rem;
          line-height: 1.6;
        }

        .category-count {
          margin: 18px 0 0;
          color: #666;
          font-size: 0.9rem;
        }

        .category-results {
          padding: 34px 0 20px;
        }

        .category-grid {
          display: grid;
          grid-template-columns: repeat(3, minmax(0, 1fr));
          gap: 28px;
        }

        .category-card {
          min-width: 0;
          padding-bottom: 24px;
          border-bottom: 1px solid #cfcfcf;
        }

        .category-card-link {
          display: block;
          color: inherit;
          text-decoration: none;
        }

        .category-image-wrapper {
          overflow: hidden;
          aspect-ratio: 16 / 10;
          margin-bottom: 15px;
          background: #ececec;
        }

        .category-image {
          display: block;
          width: 100%;
          height: 100%;
          object-fit: cover;
          transition: transform 0.25s ease;
        }

        .category-card-link:hover .category-image {
          transform: scale(1.02);
        }

        .category-card-title {
          margin: 8px 0 10px;
          color: #111;
          font-size: clamp(1.35rem, 2.4vw, 2rem);
          line-height: 1.12;
          transition: color 0.2s ease;
        }

        .category-card-link:hover .category-card-title {
          color: #2e7d32;
        }

        .category-card-description {
          display: -webkit-box;
          margin: 0 0 12px;
          overflow: hidden;
          color: #4b4b4b;
          line-height: 1.55;
          -webkit-box-orient: vertical;
          -webkit-line-clamp: 3;
        }

        .category-card-date {
          color: #666;
          font-size: 0.82rem;
        }

        .category-empty {
          margin: 0;
          padding: 42px 0;
          border-bottom: 1px solid #cfcfcf;
          color: #555;
          font-size: 1.05rem;
        }

        @media (max-width: 900px) {
          .category-grid {
            grid-template-columns: repeat(2, minmax(0, 1fr));
          }
        }

        @media (max-width: 640px) {
          .category-navigation {
            align-items: flex-start;
            gap: 12px;
          }

          .category-header {
            padding: 42px 0 30px;
          }

          .category-grid {
            grid-template-columns: 1fr;
          }
        }
      `}</style>
    </main>
  );
}

import { generatedPosts } from "@/lib/generated-posts";
import Link from "next/link";
import Image from "next/image";

export const metadata = {
  title: "Blog | Tupiniquim",
  description:
    "Conteúdos sobre tecnologia, negócios e inovação da Tupiniquim.",
};

export default function BlogPage() {
  const posts = generatedPosts;

  return (
    <main>
      {/* HERO */}
      <section className="hero-blog">
        <h1>Blog Tupiniquim</h1>
        <p>Conteúdos sobre tecnologia e crescimento digital.</p>
      </section>

      {/* LISTA */}
      <section className="list">
        {posts.map((post) => (
          <Link
            key={post.slug}
            href={`/blog/${post.slug}`}
            style={{ textDecoration: "none", color: "inherit" }}
          >
            <div className="post-card">
              {post.image && (
                <Image
                  src={post.image}
                  alt={post.title}
                  width={120}
                  height={80}
                  className="thumb"
                />
              )}

              <div>
                <h2 className="post-title">{post.title}</h2>
                <p>{post.date}</p>
              </div>
            </div>
          </Link>
        ))}
      </section>

      <style>{`
        .hero-blog {
          background: linear-gradient(120deg,#111,#1B5E20);
          color: white;
          padding: 40px;
          border-radius: 10px;
          margin-bottom: 30px;
        }

        .list {
          display: flex;
          flex-direction: column;
          gap: 16px;
        }

        .post-card {
          display: flex;
          gap: 16px;
          align-items: center;
          padding: 16px;
          border: 1px solid #ddd;
          border-radius: 10px;
          background: #fff;
          transition: 0.2s;
          cursor: pointer;
        }

        .post-card:hover {
          border-color: #2E7D32;
        }

        .post-title {
          margin-bottom: 5px;
          transition: 0.2s;
        }

        .post-card:hover .post-title {
          color: #2E7D32;
        }

        .thumb {
          border-radius: 8px;
          object-fit: cover;
        }
      `}</style>
    </main>
  );
}

import { generatedPosts } from "@/lib/generated-posts";
import {
  getBlogCategories,
  getBlogCategoryByValue,
} from "@/lib/blog-categories";
import Link from "next/link";
import Image from "next/image";

export const metadata = {
  title: "Blog | Tupiniquim",
  description:
    "Conteúdos sobre tecnologia, negócios e inovação da Tupiniquim.",
};

function formatDate(date: string) {
  const parsedDate = new Date(`${date}T12:00:00`);

  if (Number.isNaN(parsedDate.getTime())) {
    return date;
  }

  return new Intl.DateTimeFormat("pt-BR", {
    day: "2-digit",
    month: "long",
    year: "numeric",
  }).format(parsedDate);
}

export default function BlogPage() {
  const posts = generatedPosts;
  const featuredPost =
    posts.find((post) => post.slug === "construindo-um-blog") ?? posts[0];
  const secondaryPosts = posts
    .filter((post) => post.slug !== featuredPost?.slug)
    .slice(0, 2);
  const categories = getBlogCategories();

  return (
    <main className="blog-page">
      {/* HERO */}
      <section className="hero-blog">
        <p className="hero-eyebrow">Conteúdo e informação</p>
        <h1>Blog Tupiniquim</h1>
        <p>Conteúdos sobre tecnologia e crescimento digital.</p>
      </section>

      {/* CATEGORIAS */}
      <nav className="category-nav" aria-label="Categorias do blog">
        <span className="category-nav-title">Editorias</span>
        <div className="category-list">
          <Link
            href="/blog"
            className="category-item category-item-active"
            aria-current="page"
          >
            Todos
          </Link>

          {categories.map((category) => (
            <Link
              className="category-item"
              href={`/blog/categoria/${category.slug}`}
              key={category.slug}
            >
              {category.label}
            </Link>
          ))}
        </div>
      </nav>

      {/* DESTAQUES EDITORIAIS */}
      {featuredPost && (
        <section
          className="editorial-grid"
          aria-label="Publicações em destaque"
        >
          <article className="lead-story">
            <Link
              href={`/blog/${featuredPost.slug}`}
              className="story-link lead-story-link"
            >
              {featuredPost.image && (
                <div className="lead-image-wrapper">
                  <Image
                    src={featuredPost.image}
                    alt={featuredPost.title}
                    width={960}
                    height={600}
                    className="lead-image"
                    priority
                  />
                </div>
              )}

              <div className="lead-content">
                <p className="story-category">
                  {getBlogCategoryByValue(featuredPost.category)?.label ??
                    featuredPost.category}
                </p>
