  ".js",
  ".jsx",
  ".mjs",
  ".cjs",
  ".json",
  ".jsonc",
  ".css",
  ".mdx",
  ".md"
]);

const BINARY_EXTENSIONS = new Set([
  ".ico",
  ".png",
  ".jpg",
  ".jpeg",
  ".gif",
  ".webp",
  ".svg",
  ".pdf",
  ".doc",
  ".docx",
  ".xls",
  ".xlsx",
  ".ppt",
  ".pptx",
  ".woff",
  ".woff2",
  ".ttf",
  ".otf",
  ".eot",
  ".sqlite",
  ".db",
  ".exe",
  ".dll",
  ".zip",
  ".tar",
  ".gz",
  ".7z",
  ".rar"
]);

const EXPECTED_EXCLUSION_REASONS = new Set([
  "sensitive_file",
  "binary_file",
  "unsupported_extension",
  "generated_output",
  "local_artifact"
]);

const INCOMPLETE_EXCLUSION_REASONS = new Set([
  "file_size_limit",
  "total_size_limit",
  "read_error"
]);

const projectMap = {
  generatedAt: new Date().toISOString(),
  project: {},
  architecture: {},
  filesystem: [],
  routes: [],
  dependencies: {},
  scripts: {},
  components: [],
  posts: [],
  importGraph: [],
